const validos = (items || []).filter(it => it?.json && Object.keys(it.json).length > 0);

const listado = validos.map((it, idx) => {
  const j = it.json || {};
  const materia  = (j.Materia ?? '').toString().trim();
  const profesor = [j.Nombres, j.Apellidos].filter(Boolean).join(' ').trim();
  const desc     = (j['Descripción'] ?? j.Descripcion ?? '').toString().trim();
  return `${idx + 1}. ${materia}\n   Profesor: ${profesor}\n   Descripción: ${desc}`;
}).join('\n\n');

return [{
  json: {
    actividades: listado || 'Sin actividades',
    actividades_count: validos.length
  },
}];

