// America/Bogota: próximo día hábil (lun–jue => mañana, vie => lunes)
const tz = 'America/Bogota';
const nowTz = new Date(new Date().toLocaleString('en-US', { timeZone: tz }));
const dow = nowTz.getDay(); // 0=Dom, 1=Lun ... 5=Vie, 6=Sáb

const addDays = (dow === 5) ? 3 : 1; // viernes => +3, demás (lun–jue) => +1
const target = new Date(nowTz);
target.setDate(target.getDate() + addDays);

const yyyy = target.getFullYear();
const mm = String(target.getMonth() + 1).padStart(2, '0');
const dd = String(target.getDate()).padStart(2, '0');

return [{ fecha_objetivo: `${yyyy}-${mm}-${dd}`, tz }];

// Toma fecha_objetivo del nodo "Determinar siguiente día hábil"
const fechaObjetivo = $('Determinar siguiente día hábil').item.json.fecha_objetivo; // "YYYY-MM-DD"

// Normaliza varios formatos a "YYYY-MM-DD"
function normalizaFecha(str) {
  const s = (str || '').toString().trim();

  // dd/mm/yyyy o dd-mm-yyyy o dd/mm/yy o dd-mm-yy (ej: "30/10/2025 (jueves)" o "28/10/25 (martes)")
  const dmY = s.match(/\b(\d{1,2})[\/-](\d{1,2})[\/-](\d{2,4})\b/);
  if (dmY) {
    const [, d, m, y] = dmY;
    // Si el año tiene 2 dígitos, asumimos 20XX
    const year = y.length === 2 ? `20${y}` : y;
    return `${year}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
  }

  // yyyy/mm/dd o yyyy-mm-dd
  const yMd = s.match(/\b(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})\b/);
  if (yMd) {
    const [, y, m, d] = yMd;
    return `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
  }

  return null;
}

// Devuelve SOLO las actividades con fecha == fechaObjetivo
const filtradas = (items || []).filter(it => {
  const j = it?.json || {};
  const f = normalizaFecha(j.fecha_de_presentacion ?? j['Fecha de presentación']);
  return f === fechaObjetivo;
});

// Importante: devolver como array de items (n8n)
return filtradas;

